import{_ as a,o as t,c as i,a0 as s}from"./chunks/framework.B_R3rS_4.js";const u=JSON.parse('{"title":"Mathematics & Shader Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"technical/math.md","filePath":"technical/math.md"}'),n={name:"technical/math.md"};function o(l,e,c,h,r,p){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="mathematics-shader-architecture" tabindex="-1">Mathematics &amp; Shader Architecture <a class="header-anchor" href="#mathematics-shader-architecture" aria-label="Permalink to &quot;Mathematics &amp; Shader Architecture&quot;">​</a></h1><p>The core magic of RTI (Reflectance Transformation Imaging) happens inside the WebGL Fragment Shaders (<code>RtiShaders.js</code>). These shaders reconstruct photorealistic lighting dynamically using pre-calculated coefficients stored in image textures.</p><p>There are two primary mathematical formulations supported by this viewer: <strong>PTM</strong> and <strong>HSH</strong>.</p><hr><h2 id="coefficient-unpacking-bias-and-scale" tabindex="-1">Coefficient Unpacking (Bias and Scale) <a class="header-anchor" href="#coefficient-unpacking-bias-and-scale" aria-label="Permalink to &quot;Coefficient Unpacking (Bias and Scale)&quot;">​</a></h2><p>Because standard images (like JPEG) only support 8-bit values per channel (0 to 255), we cannot directly store the complex floating-point coefficients required for RTI. To get around this, the RTI compiler calculates the global minimum (<code>Bias</code>) and range (<code>Scale</code>) for each coefficient layer across the entire image.</p><p>In the shader, we reconstruct the exact mathematical floating-point value using:</p><div class="language-glsl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">glsl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Example for a single coefficient layer</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">vec3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> coefficient </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> texture2D</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tex0, uv).xyz;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">coefficient </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> coefficient </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> uBias </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> uScale;</span></span></code></pre></div><p><em>(Note: Although historically named <code>Bias</code> and <code>Scale</code> in the <code>info.xml</code> file, the <code>Bias</code> tag actually holds the multiplier and the <code>Scale</code> tag holds the additive offset).</em></p><hr><h2 id="_1-polynomial-texture-mapping-ptm" tabindex="-1">1. Polynomial Texture Mapping (PTM) <a class="header-anchor" href="#_1-polynomial-texture-mapping-ptm" aria-label="Permalink to &quot;1. Polynomial Texture Mapping (PTM)&quot;">​</a></h2><p>PTM uses a 2D biquadratic polynomial to estimate the reflectance. It assumes the light direction <code>(u, v)</code> is projected onto a flat 2D plane.</p><p><strong>The Equation:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Luminance = a0*u² + a1*v² + a2*u*v + a3*u + a4*v + a5</span></span></code></pre></div><p>Where:</p><ul><li><code>u</code> and <code>v</code> are the X and Y components of the normalized light direction vector.</li><li><code>a0</code> through <code>a5</code> are the 6 coefficients extracted from 2 LRGB textures.</li></ul><p>The final color is computed by taking the base RGB texture and multiplying it by this reconstructed <code>Luminance</code> scalar.</p><hr><h2 id="_2-hemispherical-harmonics-hsh" tabindex="-1">2. Hemispherical Harmonics (HSH) <a class="header-anchor" href="#_2-hemispherical-harmonics-hsh" aria-label="Permalink to &quot;2. Hemispherical Harmonics (HSH)&quot;">​</a></h2><p>HSH is a more modern, physically accurate formulation based on Spherical Harmonics, but restricted to the upper hemisphere (since light cannot shine from underneath a flat surface).</p><p>Instead of a simple polynomial, HSH uses 4 complex basis functions based on the spherical coordinates <code>phi</code> (azimuth) and <code>theta</code> (elevation) of the light vector.</p><p><strong>The Basis Functions:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>l0 = 1.0 / sqrt(2 * π)</span></span>
<span class="line"><span>l1 = sqrt(6 / π) * cos(phi) * sqrt(max(0, cos(theta) - cos²(theta)))</span></span>
<span class="line"><span>l2 = sqrt(3 / 2π) * (2 * cos(theta) - 1)</span></span>
<span class="line"><span>l3 = sqrt(6 / π) * sin(phi) * sqrt(max(0, cos(theta) - cos²(theta)))</span></span></code></pre></div><p><strong>The Equation:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Color (RGB) = (c0 * l0) + (c1 * l1) + (c2 * l2) + (c3 * l3)</span></span></code></pre></div><p>Unlike PTM which uses a single luminance multiplier, HSH stores these coefficients separately for the Red, Green, and Blue channels. This means HSH uses 4 complete RGB textures (12 coefficients in total per pixel) to reconstruct color shifts depending on the light angle, providing much higher fidelity and more accurate highlights.</p><h3 id="interaction-constraints" tabindex="-1">Interaction Constraints <a class="header-anchor" href="#interaction-constraints" aria-label="Permalink to &quot;Interaction Constraints&quot;">​</a></h3><p>To prevent the equations from breaking down at extreme grazing angles (where the light is exactly parallel to the surface, <code>nz = 0</code>), the UI interaction in <code>RtiViewer.vue</code> mathematically clamps the maximum light radius to <code>0.95</code>. This ensures the light always has a slight elevation, preventing the image from turning completely black when the mouse is pulled far outside the active area.</p><hr><h2 id="_3-advanced-rendering-modes" tabindex="-1">3. Advanced Rendering Modes <a class="header-anchor" href="#_3-advanced-rendering-modes" aria-label="Permalink to &quot;3. Advanced Rendering Modes&quot;">​</a></h2><p>In addition to standard diffuse and specular shading, the viewer implements specialized mathematical visualizations to aid scientific analysis:</p><h3 id="slope-heatmap" tabindex="-1">Slope Heatmap <a class="header-anchor" href="#slope-heatmap" aria-label="Permalink to &quot;Slope Heatmap&quot;">​</a></h3><p>Rather than displaying the normal vector&#39;s <code>(x,y,z)</code> values directly as RGB colors, the Slope Heatmap calculates the absolute steepness of the surface at every pixel. The steepness is derived directly from the Z-component of the normal vector:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Steepness = 1.0 - N.z</span></span></code></pre></div><p>If a pixel points directly at the camera (<code>N.z = 1.0</code>), the steepness is 0 (flat). As the surface curves away, <code>N.z</code> drops, increasing the steepness. This scalar value is then passed through a <code>mix()</code> function in the shader to output a blue-to-red thermal gradient, visually amplifying shallow scratches.</p><h3 id="dual-light-opposing-raking-light" tabindex="-1">Dual Light (Opposing Raking Light) <a class="header-anchor" href="#dual-light-opposing-raking-light" aria-label="Permalink to &quot;Dual Light (Opposing Raking Light)&quot;">​</a></h3><p>This mode calculates two simultaneous lighting equations in a single pass. It uses the primary user-defined light direction <code>L1</code> and computes a virtual secondary light <code>L2</code> placed exactly on the opposite side:</p><div class="language-glsl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">glsl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">vec3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> L2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> vec3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">L1.x, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">L1.y, L1.z);</span></span></code></pre></div><p>The shader calculates the resulting luminance for both light vectors independently. <code>L1</code> is tinted red <code>vec3(1.0, 0.3, 0.1)</code>, and <code>L2</code> is tinted blue <code>vec3(0.1, 0.5, 1.0)</code>. The sum of these two colored results provides extreme edge-contrast enhancement, highly useful for deciphering tool marks in archaeology.</p>`,39)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
